## switch文の基本構文

```javascript
switch (式) {
  case 値1:
    // 式 === 値1 のとき実行
    break;
  case 値2:
    // 式 === 値2 のとき実行
    break;
  default:
    // どのcaseにも一致しないとき実行
}
```

**重要：** 各 `case` の末尾に `break` がないと、次の `case` の処理も続けて実行されます（フォールスルー）。意図しない場合はバグになるので必ず `break` を書きましょう。

### if-else ifとswitchの比較

```javascript
// if-else if（同じ変数を繰り返し書く）
if (pageType === 'top') {
  eventName = 'view_top';
} else if (pageType === 'product') {
  eventName = 'view_item';
} else if (pageType === 'cart') {
  eventName = 'view_cart';
} else if (pageType === 'thankyou') {
  eventName = 'purchase';
}

// switch（比較対象が1つにまとまり読みやすい）
switch (pageType) {
  case 'top':
    eventName = 'view_top';
    break;
  case 'product':
    eventName = 'view_item';
    break;
  case 'cart':
    eventName = 'view_cart';
    break;
  case 'thankyou':
    eventName = 'purchase';
    break;
  default:
    eventName = 'view_page';
}
```

### フォールスルーを意図的に使うパターン

複数のケースで同じ処理をしたいときは、意図的にフォールスルーを活用できます。

```javascript
<script>
  var channel = {{Traffic Source}};
  var channelGroup;

  switch (channel) {
    case 'google_cpc':
    case 'yahoo_cpc':
    case 'line_ads':
      // 複数のケースで同じ処理
      channelGroup = 'paid_search';
      break;
    case 'google_organic':
    case 'yahoo_organic':
      channelGroup = 'organic_search';
      break;
    case 'email':
    case 'newsletter':
      channelGroup = 'email_marketing';
      break;
    default:
      channelGroup = 'other';
  }

  window.dataLayer = window.dataLayer || [];
  window.dataLayer.push({
    'event': 'set_channel_group',
    'channel_group': channelGroup
  });
</script>
```

### GA4イベントパラメータのマッピング例

```javascript
<script>
  var productCategory = {{Product Category}};
  var ga4Category;

  switch (productCategory) {
    case 'mens-wear':
    case 'mens-shoes':
      ga4Category = 'メンズ';
      break;
    case 'womens-wear':
    case 'womens-shoes':
      ga4Category = 'レディース';
      break;
    case 'kids':
      ga4Category = 'キッズ';
      break;
    default:
      ga4Category = 'その他';
  }

  window.dataLayer.push({
    'event': 'view_item',
    'item_category': ga4Category
  });
</script>
```

